#!/usr/bin/env node
/**
 * build/build-paste-bundle.js
 *
 * Generates dist/INSTALL_PASTE.md — a single Markdown document with one
 * copy-paste block per source file. End users open the Apps Script editor,
 * create matching files, and paste each block. No clasp, no Node, no CLI.
 *
 * Run from repo root:  node build/build-paste-bundle.js
 *
 * Pure stdlib, no dependencies.
 */

const fs = require('fs');
const path = require('path');

const ROOT = path.resolve(__dirname, '..');
const SRC = path.join(ROOT, 'src');
const OUT_DIR = path.join(ROOT, 'dist');
const OUT = path.join(OUT_DIR, 'INSTALL_PASTE.md');

function listSrc() {
  const files = fs.readdirSync(SRC).sort();
  // appsscript.json last so it's pasted after enabling manifest visibility
  const order = (name) => {
    if (name === 'Code.js') return 0;
    if (name.endsWith('.js')) return 1;
    if (name.endsWith('.html')) return 2;
    if (name === 'appsscript.json') return 3;
    return 9;
  };
  return files.sort((a, b) => order(a) - order(b) || a.localeCompare(b));
}

function fenceFor(name) {
  if (name.endsWith('.html')) return 'html';
  if (name.endsWith('.json')) return 'json';
  return 'javascript';
}

function blockTitleAndInstructions(name) {
  const base = name.replace(/\.[^.]+$/, '');
  if (name === 'appsscript.json') {
    return {
      title: 'Manifest — `appsscript.json`',
      instructions:
        'In the Apps Script editor click the **gear icon** (Project Settings) on the left sidebar → ' +
        'check **"Show appsscript.json manifest file in editor"** → return to the Editor → ' +
        'open the existing `appsscript.json` and replace its contents with the block below.'
    };
  }
  if (name.endsWith('.html')) {
    return {
      title: `HTML — \`${base}.html\``,
      instructions:
        `Click the **+** next to "Files" → **HTML** → name it \`${base}\` → paste the block below.`
    };
  }
  // .js
  return {
    title: `Script — \`${base}.gs\``,
    instructions:
      `Click the **+** next to "Files" → **Script** → name it \`${base}\` → ` +
      `delete any default content → paste the block below. ` +
      (name === 'Code.js'
        ? '(The default `Code.gs` already exists — open it and replace its contents.)'
        : '')
  };
}

function build() {
  if (!fs.existsSync(OUT_DIR)) fs.mkdirSync(OUT_DIR, { recursive: true });
  const files = listSrc();
  const parts = [];

  parts.push('# Zoter Toolkit — Paste Install Bundle');
  parts.push('');
  parts.push(
    '> **Auto-generated by `build/build-paste-bundle.js`. Do not edit by hand.**'
  );
  parts.push('');
  parts.push(
    'This file contains every source file in the project as a copy-paste block. ' +
      'Use it together with [`INSTALL.md`](../INSTALL.md) to install the add-on into your ' +
      'Google account without using the command line.'
  );
  parts.push('');
  parts.push('## Quick start');
  parts.push('');
  parts.push('1. Open https://script.google.com → **+ New project**.');
  parts.push('2. Rename the project to **Zoter Toolkit** (top-left).');
  parts.push(
    '3. Paste each block below into a matching file in the script editor (instructions per block).'
  );
  parts.push('4. Click **Save** (disk icon).');
  parts.push(
    '5. **Deploy → Test deployments → Install** → choose **Editor add-on**, click **Done**.'
  );
  parts.push(
    '6. Open any Google Doc → menu **Extensions → Zoter Toolkit → Open sidebar** appears.'
  );
  parts.push('');
  parts.push(
    'Full instructions, prerequisites, and troubleshooting live in [`INSTALL.md`](../INSTALL.md).'
  );
  parts.push('');
  parts.push('---');
  parts.push('');

  for (const name of files) {
    const filePath = path.join(SRC, name);
    const content = fs.readFileSync(filePath, 'utf8').replace(/\r\n/g, '\n');
    const meta = blockTitleAndInstructions(name);
    parts.push(`## ${meta.title}`);
    parts.push('');
    parts.push(meta.instructions);
    parts.push('');
    parts.push('```' + fenceFor(name));
    parts.push(content.replace(/\n+$/, ''));
    parts.push('```');
    parts.push('');
  }

  parts.push('---');
  parts.push('');
  parts.push(
    '_Generated from ' +
      files.length +
      ' files in `src/`. Re-run `node build/build-paste-bundle.js` after any source change._'
  );
  parts.push('');

  fs.writeFileSync(OUT, parts.join('\n'), 'utf8');
  console.log('Wrote', path.relative(ROOT, OUT), '(' + files.length + ' files)');
}

build();
